for business in biz:
    desc = business.get('description', '')
    biz_id = business.get('business_id', '')

    # Find category list
    cat_text = ''

    # Method 1: "services in ..."
    if 'services in' in desc.lower():
        match = re.search(r'services in ([^\.]+)', desc, re.IGNORECASE)
        if match:
            cat_text = match.group(1)

    # Method 2: "including ..."  
    if not cat_text and 'including' in desc.lower():
        match = re.search(r'including ([^\.]+)', desc, re.IGNORECASE)
        if match:
            cat_text = match.group(1)

    # Method 3: "fields of ..."
    if not cat_text and 'fields of' in desc.lower():
        match = re.search(r'fields of ([^\.]+)', desc, re.IGNORECASE)
        if match:
            cat_text = match.group(1)

    if cat_text:
        # Clean up
        if cat_text.endswith('.'):
            cat_text = cat_text[:-1]

        # Split categories
        categories = re.split(r',\s+|\sand\s', cat_text)
        clean_categories = []

        for cat in categories:
            cat = cat.strip()
            if cat.startswith('and '):
                cat = cat[4:]
            cat = cat.rstrip('.')
            if len(cat) > 1:
                clean_categories.append(cat)
                category_counts[cat] += 1

        if clean_categories:
            business_categories[biz_id] = clean_categories

if not category_counts:
